  1	import * as React from 'react';
  2	import { getUID, StorageConsumerModel } from '@odf/shared';
  3	import {
  4	  getName,
  5	  ModalFooter,
  6	  StorageClassModel,
  7	  StorageClassResourceKind,
  8	  StorageConsumerKind,
  9	  useCustomTranslation,
 10	  VolumeSnapshotClassKind,
 11	  VolumeSnapshotClassModel,
 12	} from '@odf/shared';
 13	import { CommonModalProps } from '@odf/shared/modals';
 14	import {
 15	  K8sModel,
 16	  k8sPatch,
 17	  useK8sWatchResource,
 18	  WatchK8sResource,
 19	} from '@openshift-console/dynamic-plugin-sdk';
 20	import { ModalComponent } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 21	import { Button, Flex, FlexItem, Modal } from '@patternfly/react-core';
 22	import { generatePatchForDistributionOfResources } from '../../components/ResourceDistribution/utils';
 23	import './storageClientAttacherComponent.scss';
 24	import { StorageConsumerTable } from './StorageConsumerTable';
 25	
 26	const storageConsumerResource: WatchK8sResource = {
 27	  isList: true,
 28	  groupVersionKind: {
 29	    group: StorageConsumerModel.apiGroup,
 30	    version: StorageConsumerModel.apiVersion,
 31	    kind: StorageConsumerModel.kind,
 32	  },
 33	};
 34	
 35	type StorageClientAttacherModalProps = {
 36	  resource: StorageClassResourceKind | VolumeSnapshotClassKind;
 37	  resourceModel: K8sModel;
 38	};
 39	
 40	export const StorageClientAttacherModal: ModalComponent<
 41	  CommonModalProps<StorageClientAttacherModalProps>
 42	> = ({ closeModal, isOpen, extraProps: { resource, resourceModel } }) => {
 43	  const resourceName = getName(resource);
 44	  const [inProgress, setProgress] = React.useState(false);
 45	  const [error, setError] = React.useState('');
 46	
 47	  const [selectedResources, setSelectedResources] = React.useState<string[]>(
 48	    []
 49	  );
 50	  const { t } = useCustomTranslation();
 51	  const [storageConsumers, loaded] = useK8sWatchResource<StorageConsumerKind[]>(
 52	    storageConsumerResource
 53	  );
 54	  const isIntialSelection = React.useRef(false);
 55	
 56	  const resourceTypeKey: keyof StorageConsumerKind['spec'] =
 57	    resourceModel.kind === StorageClassModel.kind
 58	      ? 'storageClasses'
 59	      : resourceModel.kind === VolumeSnapshotClassModel.kind
 60	        ? 'volumeSnapshotClasses'
 61	        : 'volumeGroupSnapshotClasses';
 62	
 63	  React.useEffect(() => {
 64	    if (loaded && !isIntialSelection.current) {
 65	      const storageConsumersWithCurrentResource = storageConsumers?.filter(
 66	        (consumer) => {
 67	          const resourceNames = consumer.spec[resourceTypeKey]?.map(
 68	            (res) => res.name
 69	          );
 70	          return resourceNames?.includes(resourceName);
 71	        }
 72	      );
 73	      setSelectedResources(storageConsumersWithCurrentResource.map(getUID));
 74	      isIntialSelection.current = true;
 75	    }
 76	  }, [
 77	    loaded,
 78	    resourceModel.kind,
 79	    storageConsumers,
 80	    resourceName,
 81	    resourceTypeKey,
 82	  ]);
 83	
 84	  const onSubmit = React.useCallback(() => {
 85	    const promises = [];
 86	    setProgress(true);
 87	    storageConsumers?.forEach((storageConsumer) => {
 88	      const isStorageConsumerSelected = selectedResources.includes(
 89	        getUID(storageConsumer)
 90	      );
 91	      const storageClassNames =
 92	        resourceModel.kind === StorageClassModel.kind &&
 93	        isStorageConsumerSelected
 94	          ? [
 95	              resourceName,
 96	              ...(storageConsumer.spec?.storageClasses?.map((sc) => sc.name) ||
 97	                []),
 98	            ]
 99	          : [
100	              ...(storageConsumer.spec?.storageClasses
101	                ?.filter((sc) => sc.name !== resourceName)
102	                ?.map((sc) => sc.name) || []),
103	            ];
104	      const volumeSnapshotClassNames =
105	        resourceModel.kind === VolumeSnapshotClassModel.kind &&
106	        isStorageConsumerSelected
107	          ? [
108	              resourceName,
109	              ...(storageConsumer.spec?.volumeSnapshotClasses?.map(
110	                (vsc) => vsc.name
111	              ) || []),
112	            ]
113	          : [
114	              ...(storageConsumer.spec?.volumeSnapshotClasses
115	                ?.filter((vsc) => vsc.name !== resourceName)
116	                .map((vsc) => vsc.name) || []),
117	            ];
118	      const patch = generatePatchForDistributionOfResources(
119	        storageConsumer,
120	        storageClassNames,
121	        volumeSnapshotClassNames
122	      );
123	      promises.push(
124	        k8sPatch({
125	          model: StorageConsumerModel,
126	          resource: storageConsumer,
127	          data: patch,
128	        })
129	      );
130	    });
131	    Promise.all(promises)
132	      .then(() => {
133	        setProgress(false);
134	        closeModal();
135	      })
136	      .catch((err) => {
137	        setProgress(false);
138	        setError(err?.message);
139	      });
140	  }, [
141	    closeModal,
142	    resourceModel.kind,
143	    resourceName,
144	    selectedResources,
145	    storageConsumers,
146	  ]);
147	
148	  return (
149	    <Modal
150	      isOpen={isOpen}
151	      onClose={closeModal}
152	      title={t('Manage distribution of Storage clients')}
153	      variant="medium"
154	    >
155	      <StorageConsumerTable
156	        loaded={loaded}
157	        resources={storageConsumers}
158	        columns={['Name', 'Cluster name', 'Last heartbeat']}
159	        selectedResources={selectedResources}
160	        setSelectedResources={setSelectedResources}
161	      />
162	      <ModalFooter inProgress={inProgress} errorMessage={error}>
163	        <Flex direction={{ default: 'row' }}>
164	          <FlexItem>
165	            <Button key="Cancel" variant="secondary" onClick={closeModal}>
166	              {t('Cancel')}
167	            </Button>
168	          </FlexItem>
169	          <FlexItem>
170	            <Button key="Confirm" variant="primary" onClick={onSubmit}>
171	              {t('Save changes')}
172	            </Button>
173	          </FlexItem>
174	        </Flex>
175	      </ModalFooter>
176	    </Modal>
177	  );
178	};

